components.OutflowTimeline:
export default function OutflowTimeline() {
  const [scheduled, setScheduled] = useState([]);
  const [recurring, setRecurring] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      tools.host_listScheduledPayments({}),
      tools.host_getRecurringInsights({})
    ]).then(([sched, rec]) => {
      setScheduled(sched.data || sched.payments || sched || []);
      setRecurring(rec.subscriptions || rec.recurring || rec.data || []);
      setLoading(false);
    });
  }, []);

  if (loading) {
    return (
      <div style={{ padding: 24, color: "var(--vendo-color-muted)", fontFamily: "var(--vendo-font-family)" }}>
        Loading upcoming payments…
      </div>
    );
  }

  const today = new Date("2026-07-21");

  const schedItems = (Array.isArray(scheduled) ? scheduled : []).map((p) => ({
    id: "sched-" + (p.id || p.payeeId || Math.random()),
    label: p.payeeName || p.name || p.descriptor || "Payment",
    amountCents: p.amountCents || p.amount || 0,
    date: p.nextDate || p.scheduledDate || p.date || null,
    type: "scheduled",
    note: p.memo || p.note || null,
  }));

  const recItems = (Array.isArray(recurring) ? recurring : []).map((r) => ({
    id: "rec-" + (r.id || r.merchant || Math.random()),
    label: r.merchant || r.name || r.descriptor || "Subscription",
    amountCents: r.amountCents || r.amount || 0,
    date: r.nextDate || r.nextBillingDate || r.renewalDate || null,
    type: "subscription",
    note: r.frequency || r.interval || null,
  }));

  const all = [...schedItems, ...recItems]
    .filter((item) => item.date)
    .sort((a, b) => new Date(a.date) - new Date(b.date));

  const totalCents = all.reduce((sum, item) => sum + (item.amountCents || 0), 0);

  const fmt_money = (cents) => {
    if (!cents && cents !== 0) return "—";
    return new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(cents / 100);
  };

  const fmt_date = (iso) => {
    if (!iso) return "—";
    const d = new Date(iso);
    if (isNaN(d)) return "—";
    const diff = Math.round((d - today) / 86400000);
    const label = diff === 0 ? "Today" : diff === 1 ? "Tomorrow" : diff < 0 ? `${Math.abs(diff)}d ago` : `In ${diff}d`;
    return {
      full: d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: d.getFullYear() !== today.getFullYear() ? "numeric" : undefined }),
      relative: label,
      diff,
    };
  };

  const typeColor = { scheduled: "#111111", subscription: "#908C85" };
  const typeLabel = { scheduled: "Scheduled", subscription: "Subscription" };

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", display: "grid", gap: 0 }}>
      {/* Hero total */}
      <div style={{
        background: "var(--vendo-color-surface)",
        border: "1px solid var(--vendo-color-border)",
        borderRadius: "var(--vendo-radius-large)",
        padding: "28px 28px 24px",
        marginBottom: 16,
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "space-between",
        flexWrap: "wrap",
        gap: 12,
      }}>
        <div>
          <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginBottom: 6, letterSpacing: "0.01em" }}>
            Total going out
          </div>
          <div style={{ fontSize: 40, fontWeight: 700, color: "var(--vendo-color-text)", letterSpacing: "-0.02em", lineHeight: 1 }}>
            {fmt_money(totalCents)}
          </div>
        </div>
        <div style={{ display: "flex", gap: 20, flexWrap: "wrap" }}>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginBottom: 2 }}>Scheduled payments</div>
            <div style={{ fontSize: 18, fontWeight: 600, color: "var(--vendo-color-text)" }}>
              {fmt_money(schedItems.reduce((s, i) => s + i.amountCents, 0))}
            </div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginBottom: 2 }}>Subscriptions</div>
            <div style={{ fontSize: 18, fontWeight: 600, color: "var(--vendo-color-text)" }}>
              {fmt_money(recItems.reduce((s, i) => s + i.amountCents, 0))}
            </div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginBottom: 2 }}>Items</div>
            <div style={{ fontSize: 18, fontWeight: 600, color: "var(--vendo-color-text)" }}>{all.length}</div>
          </div>
        </div>
      </div>

      {/* Timeline */}
      {all.length === 0 ? (
        <div style={{
          background: "var(--vendo-color-surface)",
          border: "1px solid var(--vendo-color-border)",
          borderRadius: "var(--vendo-radius-large)",
          padding: 32,
          textAlign: "center",
          color: "var(--vendo-color-muted)",
          fontSize: 15,
        }}>
          Nothing scheduled — you're all clear.
        </div>
      ) : (
        <div style={{
          background: "var(--vendo-color-surface)",
          border: "1px solid var(--vendo-color-border)",
          borderRadius: "var(--vendo-radius-large)",
          overflow: "hidden",
        }}>
          {all.map((item, idx) => {
            const d = fmt_date(item.date);
            const isLast = idx === all.length - 1;
            const isSoon = d.diff >= 0 && d.diff <= 3;
            return (
              <div key={item.id} style={{
                display: "grid",
                gridTemplateColumns: "80px 1fr auto",
                alignItems: "center",
                gap: 16,
                padding: "14px 24px",
                borderBottom: isLast ? "none" : "1px solid var(--vendo-color-border)",
              }}>
                {/* Date column */}
                <div style={{ textAlign: "left" }}>
                  <div style={{
                    fontSize: 13,
                    fontWeight: 600,
                    color: isSoon ? "var(--vendo-color-text)" : "var(--vendo-color-muted)",
                  }}>
                    {d.full}
                  </div>
                  <div style={{
                    fontSize: 11,
                    color: isSoon ? "var(--vendo-color-accent)" : "var(--vendo-color-muted)",
                    marginTop: 1,
                    fontWeight: isSoon ? 600 : 400,
                  }}>
                    {d.relative}
                  </div>
                </div>

                {/* Label + type */}
                <div style={{ display: "flex", alignItems: "center", gap: 10, minWidth: 0 }}>
                  <div style={{
                    width: 8,
                    height: 8,
                    borderRadius: "50%",
                    background: item.type === "scheduled" ? "var(--vendo-color-text)" : "var(--vendo-color-muted)",
                    flexShrink: 0,
                  }}/>
                  <div style={{ minWidth: 0 }}>
                    <div style={{
                      fontSize: 15,
                      fontWeight: 500,
                      color: "var(--vendo-color-text)",
                      whiteSpace: "nowrap",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                    }}>
                      {item.label}
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 2 }}>
                      <span style={{
                        fontSize: 11,
                        color: "var(--vendo-color-muted)",
                        background: "var(--vendo-color-background)",
                        border: "1px solid var(--vendo-color-border)",
                        borderRadius: "var(--vendo-radius-small)",
                        padding: "1px 6px",
                        fontWeight: 500,
                      }}>
                        {typeLabel[item.type]}
                      </span>
                      {item.note && (
                        <span style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>{item.note}</span>
                      )}
                    </div>
                  </div>
                </div>

                {/* Amount */}
                <div style={{
                  fontSize: 16,
                  fontWeight: 600,
                  color: "var(--vendo-color-text)",
                  textAlign: "right",
                  whiteSpace: "nowrap",
                }}>
                  {fmt_money(item.amountCents)}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
